{
  "name": "pi-skills",
  "version": "1.0.0",
  "description": "Personal pi skills collection",
  "scripts": {
    "test": "tsx --test skills/posthog-skill/scripts/__tests__/*.test.ts skills/exa-search/scripts/__tests__/*.test.ts",
    "test:live": "POSTHOG_TEST_LIVE=1 tsx --test skills/posthog-skill/scripts/__tests__/*.test.ts skills/exa-search/scripts/__tests__/*.test.ts",
    "lint": "eslint skills/",
    "format": "prettier --write skills/",
    "format:check": "prettier --check skills/"
  },
  "keywords": [
    "pi-package"
  ],
  "author": "",
  "license": "ISC",
  "packageManager": "pnpm@10.30.1",
  "private": "true",
  "pi": {
    "skills": [
      "./skills"
    ]
  },
  "type": "module",
  "dependencies": {
    "exa-js": "^2.10.0"
  },
  "devDependencies": {
    "@eslint/js": "^10.0.1",
    "@types/node": "^25.5.0",
    "eslint": "^10.1.0",
    "prettier": "^3.8.1",
    "tsx": "^4.21.0",
    "typescript": "^6.0.2",
    "typescript-eslint": "^8.57.2"
  }
}
